def perceive(data):
    # data is a telemetry sample, e.g. {"attack_pps": 750000, "legit_pps": 18000}.
    out = {}
    if isinstance(data, dict):
        if "attack_pps" in data:
            out["attack_pps"] = int(data["attack_pps"])
        if "legit_pps" in data:
            out["legit_pps"] = int(data["legit_pps"])
    return out
